```powershell
# Compiling du C# pour étendre PowerShell
Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;

public class NativeMethods {
    [DllImport("kernel32.dll")]
    public static extern IntPtr GetConsoleWindow();

    [DllImport("user32.dll")]
    public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);

    public static void HideConsole() {
        IntPtr hwnd = GetConsoleWindow();
        ShowWindow(hwnd, 0);
    }
}
'@

# Classe utilitaire .NET
Add-Type -TypeDefinition @'
using System;
using System.Security.Cryptography;
using System.Text;

public class CryptoHelper {
    public static string HashSHA256(string input) {
        using var sha = SHA256.Create();
        var bytes = sha.ComputeHash(Encoding.UTF8.GetBytes(input));
        return BitConverter.ToString(bytes).Replace("-", "").ToLower();
    }

    public static string GenerateToken(int length = 32) {
        var bytes = new byte[length];
        RandomNumberGenerator.Fill(bytes);
        return Convert.ToBase64String(bytes);
    }
}
'@

[CryptoHelper]::HashSHA256("hello")   # hash SHA-256
[CryptoHelper]::GenerateToken()        # token aléatoire
```

```powershell
# ScriptBlocks comme first-class citizens
$multiplier = { param($n, $factor) $n * $factor }
& $multiplier 5 3   # 15

# Currying via closures
function Make-Multiplier {
    param($factor)
    return { param($n) $n * $factor }.GetNewClosure()
}

$double  = Make-Multiplier 2
$triple  = Make-Multiplier 3
& $double 5   # 10
& $triple 5   # 15

# Pipeline de transformations
$pipeline = @(
    { $_ * 2 },
    { $_ + 1 },
    { [math]::Pow($_, 2) }
)

$value = 3
foreach ($step in $pipeline) {
    $value = $value | ForEach-Object $step
}
Write-Host $value  # ((3*2)+1)^2 = 49

# Mémoïsation
function Memoize {
    param([scriptblock]$Fn)
    $cache = @{}
    return {
        param($key)
        if (-not $cache.ContainsKey($key)) {
            $cache[$key] = & $Fn $key
        }
        $cache[$key]
    }.GetNewClosure()
}
```

